import { PrismaClient } from '@prisma/client';
import Redis from 'ioredis';
import { Kafka } from 'kafkajs';

const prisma = new PrismaClient();
const redis = new Redis();
const kafka = new Kafka({ clientId: 'identity-service', brokers: ['kafka-broker:9092'] });

async function validateUser(username: string, password: string): Promise<boolean> {
    const user = await prisma.user.findUnique({
        where: { username },
    });

    if (!user) {
        return false;
    }

    const isValidPassword = await verifyPassword(password, user.passwordHash);
    return isValidPassword;
}

async function verifyPassword(inputPassword: string, storedHash: string): Promise<boolean> {
    // Implement password verification logic here
    return inputPassword === storedHash; // Simplified for example
}

async function getUserRoles(username: string): Promise<string[]> {
    const cachedRoles = await redis.get(`roles:${username}`);
    if (cachedRoles) {
        return JSON.parse(cachedRoles);
    }

    const user = await prisma.user.findUnique({
        where: { username },
        include: { roles: true },
    });

    if (!user) {
        return [];
    }

    await redis.set(`roles:${username}`, JSON.stringify(user.roles));
    return user.roles.map(role => role.name);
}

async function publishUserEvent(username: string, eventType: string): Promise<void> {
    const producer = kafka.producer();
    await producer.connect();
    await producer.send({
        topic: 'user-events',
        messages: [{ value: JSON.stringify({ username, eventType }) }],
    });
    await producer.disconnect();
}

export { validateUser, getUserRoles, publishUserEvent };
